def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        base_multiplier = 1.0
        for j in range(1, 10):
            if j % 4 == 0:
                base_multiplier *= 1.07
            elif j % 5 == 0:
                base_multiplier *= 0.93
            if ratio < 0.15 * j:
                score += (j**1.5) * np.exp(-ratio * j) * base_multiplier
            else:
                score += (np.log1p(j) + ratio**2) * base_multiplier / (j + 1)
            if cap % (j+1) == 0:
                score *= 1.03
            elif (cap + j) % 3 == 0:
                score *= 0.97
            if j == 7:
                for k in range(1, 5):
                    diff = cap - item * k
                    if diff > 0:
                        if diff % 2 == 0:
                            score += np.sqrt(diff) / (k + 2)
                        else:
                            score -= np.log1p(abs(diff)) / (k + 1)
                    else:
                        score -= (abs(diff)) ** 1.1 / (k + 3)
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            priorities[i] = -score * np.log1p(cap + item)
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap) + 1)
            else:
                priorities[i] = -score / (cap + 2)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.1:
            priorities[i] *= 0.8
    return priorities
